INSERT INTO public.platform_settings (key, value) VALUES
  ('admin_notify_email', ''),
  ('admin_notify_email_enabled', 'true'),
  ('admin_notify_email_ticket_subject', 'Tiket Bantuan Baru — {school}'),
  ('admin_notify_email_ticket_html', '&lt;div style="font-family:Inter,Arial,sans-serif;max-width:560px;margin:0 auto;padding:24px;background:#F4F5FB;color:#0b1020"&gt;&lt;div style="background:#ffffff;border-radius:16px;padding:24px;box-shadow:0 4px 16px rgba(15,23,42,.06)"&gt;&lt;div style="display:inline-block;background:#5B6CF9;color:#fff;padding:6px 12px;border-radius:999px;font-size:12px;font-weight:600;margin-bottom:12px"&gt;Tiket Bantuan Baru&lt;/div&gt;&lt;h2 style="margin:0 0 16px;font-size:18px;color:#0b1020"&gt;{subject}&lt;/h2&gt;&lt;table style="width:100%;font-size:13px;color:#334155;border-collapse:collapse"&gt;&lt;tr&gt;&lt;td style="padding:6px 0;color:#64748b;width:100px"&gt;Sekolah&lt;/td&gt;&lt;td style="padding:6px 0;font-weight:600"&gt;{school}&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style="padding:6px 0;color:#64748b"&gt;Pengirim&lt;/td&gt;&lt;td style="padding:6px 0;font-weight:600"&gt;{user}&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style="padding:6px 0;color:#64748b"&gt;Prioritas&lt;/td&gt;&lt;td style="padding:6px 0;font-weight:600;text-transform:capitalize"&gt;{priority}&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style="padding:6px 0;color:#64748b"&gt;Waktu&lt;/td&gt;&lt;td style="padding:6px 0"&gt;{time}&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;div style="margin-top:16px;padding:14px;background:#F4F5FB;border-radius:10px;font-size:13px;line-height:1.5;white-space:pre-wrap"&gt;{message}&lt;/div&gt;&lt;p style="margin-top:20px;font-size:11px;color:#94a3b8"&gt;Notifikasi otomatis dari ATSkolla — buka Super Admin › Tiket Bantuan untuk membalas.&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;')
